+fn zone_policy_with_ceiling(caps: &[&str]) -> ZonePolicyObject {
+    let zone = ZoneId::work();
+    ZonePolicyObject {
+        header: fcp_core::ObjectHeader {
+            schema: fcp_cbor::SchemaId::new("fcp.test", "ZonePolicyObject", Version::new(1, 0, 0)),
+            zone_id: zone.clone(),
