+            provenance: Provenance::new(zone.clone()),
+            refs: vec![],
+            foreign_refs: vec![],
+            ttl_secs: None,
+            placement: None,
+        },
+        zone_id: zone,
+        principal_allow: vec![],
+        principal_deny: vec![],
+        connector_allow: vec![],
+        connector_deny: vec![],
+        capability_allow: vec![],
+        capability_deny: vec![],
+        capability_ceiling: caps
