+fn test_coverage(
+    object_id: ObjectId,
+    distinct_nodes: usize,
+    coverage_bps: u32,
+    source_symbols: u32,
+) -> CoverageEvaluation {
+    CoverageEvaluation {
+        object_id,
+        distinct_nodes,
+        max_node_fraction_bps: if distinct_nodes > 0 {
+            10000 / distinct_nodes as u16
+        } else {
+            10000
+        },
+        coverage_bps,
+        is_available: coverage_bps >= 10000,
+        total_symbols: (coverage_bps as u32 * source_symbols) / 10000,
+        source_symbols,
+    }
+}
